    {
      "start_sec": 1.54,
      "end_sec": 1.56,
      "text": "Մորքուր ջան, չէինք իմացել։"
    },
    {
      "start_sec": 1.56,
      "end_sec": 2.0,
      "text": "Մեր ամբողջ վարչության կողմից ցավակցում եմ։"
    },
    {
      "start_sec": 2.0,
      "end_sec": 2.03,
      "text": "Բայց ես ձեզ ուրիշ բան եմ հարցնում։"
    },
    {
      "start_sec": 2.03,
      "end_sec": 2.06,
      "text": "Ձեր կովերը... կովերը ո՞ւր են։"
    },
    {
      "start_sec": 2.06,
      "end_sec": 2.09,
      "text": "Սպասի, տղա ջան, դու ուշադիր լսի:"
