    {
      "start_sec": 2.09,
      "end_sec": 2.17,
      "text": "Էս մեր ցուլը, էս մեր Վալմոնտը որ մեզանից հեռացավ, մենք մի հատ լավ լացեցինք։"
    },
    {
      "start_sec": 2.17,
      "end_sec": 2.2,
      "text": "Բայց հետո էդ լացուկոծը թարգեցինք։"
    },
    {
      "start_sec": 2.2,
      "end_sec": 2.26,
      "text": "Էս մեր գյուղի տղամարդիկ հավաքվեցին, համախմբվեցին ու անցան գործի։"
    },
    {
      "start_sec": 2.27,
      "end_sec": 2.33,
      "text": "Հիմի ամեն առավոտ էս մեր տղամարդիկ բոլոր կովերին հավաքում են ու տանում են դաշտ։"
    },
    {
      "start_sec": 2.33,
      "end_sec": 2.37,
      "text": "Ընդեղ մի հատ հաճելի երաժշտություն են միացնում, խոսքի օրինակ՝ բլյուզ։"
    },
    {
      "start_sec": 2.37,
      "end_sec": 2.42,
      "text": "Ու էդ երաժշտության տակ ցուլի պարտականություններն են կատարում։"
    },
    {
      "start_sec": 2.42,
      "end_sec": 2.47,
